674	impl<T> Drop for Sender<T> {
675	    fn drop(&mut self) {
676	        unsafe {
677	            match &self.flavor {
678	                SenderFlavor::Array(chan) => chan.release(|c| c.disconnect_senders()),
679	                SenderFlavor::List(chan) => chan.release(|c| c.disconnect_senders()),
680	                SenderFlavor::Zero(chan) => chan.release(|c| c.disconnect()),
681	            }
682	        }
683	    }
684	}
