686	impl<T> Clone for Sender<T> {
687	    fn clone(&self) -> Self {
688	        let flavor = match &self.flavor {
689	            SenderFlavor::Array(chan) => SenderFlavor::Array(chan.acquire()),
690	            SenderFlavor::List(chan) => SenderFlavor::List(chan.acquire()),
691	            SenderFlavor::Zero(chan) => SenderFlavor::Zero(chan.acquire()),
692	        };
693	
694	        Self { flavor }
695	    }
696	}
