779	        match &self.flavor {
780	            ReceiverFlavor::Array(chan) => chan.try_recv(),
781	            ReceiverFlavor::List(chan) => chan.try_recv(),
782	            ReceiverFlavor::Zero(chan) => chan.try_recv(),
783	            ReceiverFlavor::At(chan) => {
784	                let msg = chan.try_recv();
785	                unsafe {
786	                    mem::transmute_copy::<Result<Instant, TryRecvError>, Result<T, TryRecvError>>(
787	                        &msg,
788	                    )
789	                }
790	            }
791	            ReceiverFlavor::Tick(chan) => {
792	                let msg = chan.try_recv();
793	                unsafe {
794	                    mem::transmute_copy::<Result<Instant, TryRecvError>, Result<T, TryRecvError>>(
795	                        &msg,
796	                    )
797	                }
798	            }
